import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async (event) => {
    event.preventDefault();
    setError('');
    setLoading(true);

    try {
      const res = await axios.post('http://localhost:3001/login', {
        email,
        username: email,
        password
      });

      if (res.data.token || res.data.success) {
        localStorage.setItem('token', res.data.token || '');
        localStorage.setItem('user', JSON.stringify(res.data.user || { email }));
        navigate('/home');
        return;
      }

      setError('Login invalido');
    } catch (err) {
      const message = err.response?.data?.message || err.response?.data?.error || 'Erro ao fazer login';
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <form style={styles.card} onSubmit={handleLogin}>
        <h1 style={styles.title}>Sistema GRC</h1>
        <p style={styles.subtitle}>Acesse sua conta para continuar</p>

        <input
          style={styles.input}
          type="email"
          placeholder="Email"
          value={email}
          onChange={(event) => setEmail(event.target.value)}
          autoComplete="email"
          required
        />

        <input
          style={styles.input}
          type="password"
          placeholder="Senha"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
          autoComplete="current-password"
          required
        />

        {error && <p style={styles.error}>{error}</p>}

        <button style={styles.button} type="submit" disabled={loading}>
          {loading ? 'Entrando...' : 'Entrar'}
        </button>
      </form>
    </div>
  );
}

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #1e3c72, #2a5298)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    padding: 20,
    boxSizing: 'border-box'
  },
  card: {
    background: '#fff',
    padding: 32,
    borderRadius: 8,
    width: '100%',
    maxWidth: 380,
    boxShadow: '0 15px 40px rgba(0,0,0,0.2)'
  },
  title: {
    margin: 0,
    color: '#1e3c72',
    textAlign: 'center'
  },
  subtitle: {
    marginTop: 8,
    marginBottom: 24,
    color: '#666',
    textAlign: 'center'
  },
  input: {
    width: '100%',
    padding: 12,
    marginBottom: 12,
    borderRadius: 8,
    border: '1px solid #ddd',
    fontSize: 14,
    boxSizing: 'border-box'
  },
  error: {
    color: '#c62828',
    marginTop: 0,
    fontSize: 14
  },
  button: {
    width: '100%',
    padding: 12,
    background: '#1e88e5',
    color: '#fff',
    border: 'none',
    borderRadius: 8,
    fontSize: 16,
    cursor: 'pointer'
  }
};

export default Login;
